// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // Helper to convert weather condition to emoji icon
  const getWeatherIcon = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('storm')) return '⛈️';
    if (conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('fog')) return '🌫️';
    return '🌤️'; // default
  };

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* City Header */}
            <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>

            {/* Main Temperature Section */}
            <Row align="center" gap="var(--ggui-spacing-4)" justify="start">
              {/* Large Weather Icon */}
              <Box>
                <Text size="4xl">{getWeatherIcon(props.condition)}</Text>
              </Box>

              {/* Temperature and Condition */}
              <Stack gap="var(--ggui-spacing-2)">
                <Heading level={1} color="var(--ggui-color-primary-600)">
                  {props.temperature}°{props.unit}
                </Heading>
                <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" size="lg">
                  {props.condition}
                </Text>
              </Stack>
            </Row>

            {/* Humidity and Wind Speed */}
            <Divider orientation="horizontal" margin="var(--ggui-spacing-3)" />
            <Row gap="var(--ggui-spacing-6)" justify="start" align="center">
              <Box>
                <Stack gap="var(--ggui-spacing-1)" align="start">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">
                    {props.humidity}%
                  </Text>
                </Stack>
              </Box>
              <Box>
                <Stack gap="var(--ggui-spacing-1)" align="start">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                  <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">
                    {props.windSpeed} km/h
                  </Text>
                </Stack>
              </Box>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>

            {props.forecast && props.forecast.length > 0 ? (
              <Row gap="var(--ggui-spacing-2)" justify="start" align="stretch" wrap={true}>
                {props.forecast.map((day, index) => (
                  <Card
                    key={index}
                    padding="var(--ggui-spacing-3)"
                    shadow="sm"
                    radius="md"
                    border={true}
                    style={{ flex: '1 1 auto', minWidth: '100px', textAlign: 'center' }}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" weight="semibold">
                        {day.day || `Day ${index + 1}`}
                      </Text>
                      <Text size="2xl">{day.icon || '🌤️'}</Text>
                      <Box>
                        <Text variant="caption" color="var(--ggui-color-onSurface)" weight="semibold">
                          {day.high}°
                        </Text>
                      </Box>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                        {day.low}°
                      </Text>
                    </Stack>
                  </Card>
                ))}
              </Row>
            ) : (
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                No forecast data available
              </Text>
            )}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State
  const [currentStep, setCurrentStep] = useState<1 | 2 | 3 | 4 | 5>(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation state
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Validation helpers
  const isValidEmail = (value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  };

  const validateName = (value: string): string => {
    if (!value.trim()) return 'Name is required';
    return '';
  };

  const validateEmail = (value: string): string => {
    if (!value.trim()) return 'Email is required';
    if (!isValidEmail(value)) return 'Please enter a valid email address';
    return '';
  };

  // Handle name change with inline validation
  const handleNameChange = (value: string) => {
    setName(value);
    if (value.trim()) {
      setNameError('');
    }
  };

  // Handle email change with inline validation
  const handleEmailChange = (value: string) => {
    setEmail(value);
    if (value.trim() && isValidEmail(value)) {
      setEmailError('');
    }
  };

  // Check if Step 1 is valid
  const isStep1Valid = (): boolean => {
    const nameErr = validateName(name);
    const emailErr = validateEmail(email);
    if (nameErr || emailErr) {
      setNameError(nameErr);
      setEmailError(emailErr);
      return false;
    }
    return true;
  };

  // Handle Next button
  const handleNext = () => {
    if (currentStep === 1) {
      if (!isStep1Valid()) return;
    }
    if (currentStep < 5) {
      setCurrentStep((currentStep + 1) as 1 | 2 | 3 | 4 | 5);
    }
  };

  // Handle Back button
  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep((currentStep - 1) as 1 | 2 | 3 | 4 | 5);
    }
  };

  // Handle toggle feature selection
  const handleFeatureToggle = (feature: string) => {
    setSelectedFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  };

  // Handle submit
  const handleSubmit = () => {
    submit({
      name,
      email,
      satisfaction: parseInt(satisfaction, 10),
      features: selectedFeatures,
      comments,
    });
  };

  // Progress bar calculation
  const progressPercent = ((currentStep - 1) / 4) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress Bar */}
        <Stack gap="var(--ggui-spacing-2)">
          <Row justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {currentStep} of 4
            </Text>
          </Row>
          <Progress value={progressPercent} max={100} size="md" />
        </Stack>

        {/* Step 1: Name & Email */}
        {currentStep === 1 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Tell us about yourself</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              We'd like to know your name and email to get started.
            </Text>
            <Stack gap="var(--ggui-spacing-3)">
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={name}
                onChange={handleNameChange}
                error={nameError}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="john@example.com"
                value={email}
                onChange={handleEmailChange}
                error={emailError}
                required
              />
            </Stack>
          </Stack>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>How satisfied are you?</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Please rate your satisfaction on a scale of 1 to 5.
            </Text>
            <RadioGroup
              label="Satisfaction Rating"
              value={satisfaction}
              onChange={setSatisfaction}
              options={props.satisfactionLabels.map((label, index) => ({
                value: String(index + 1),
                label,
              }))}
              direction="vertical"
            />
          </Stack>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>What features interest you?</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Select all that apply.
            </Text>
            <Stack gap="var(--ggui-spacing-2)">
              {props.featureOptions.map((feature) => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={selectedFeatures.includes(feature)}
                  onChange={() => handleFeatureToggle(feature)}
                />
              ))}
            </Stack>
          </Stack>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Any additional comments?</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Please share any other feedback or comments (optional).
            </Text>
            <TextArea
              label="Comments"
              placeholder="Type your comments here..."
              value={comments}
              onChange={setComments}
              rows={5}
              maxLength={500}
              showCount
            />
          </Stack>
        )}

        {/* Step 5: Review */}
        {currentStep === 5 && (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2}>Review Your Answers</Heading>
            <Card padding="var(--ggui-spacing-4)" shadow="sm">
              <Stack gap="var(--ggui-spacing-3)">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Name
                  </Text>
                  <Text variant="body">{name}</Text>
                </Stack>
                <Divider margin="var(--ggui-spacing-2)" />
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Email
                  </Text>
                  <Text variant="body">{email}</Text>
                </Stack>
                <Divider margin="var(--ggui-spacing-2)" />
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Satisfaction
                  </Text>
                  <Text variant="body">{props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}</Text>
                </Stack>
                <Divider margin="var(--ggui-spacing-2)" />
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Features of Interest
                  </Text>
                  {selectedFeatures.length > 0 ? (
                    <Stack gap="var(--ggui-spacing-1)">
                      {selectedFeatures.map((feature) => (
                        <Text key={feature} variant="body">
                          • {feature}
                        </Text>
                      ))}
                    </Stack>
                  ) : (
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                      None selected
                    </Text>
                  )}
                </Stack>
                <Divider margin="var(--ggui-spacing-2)" />
                <Stack gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Comments
                  </Text>
                  <Text variant="body">
                    {comments || '(No comments provided)'}
                  </Text>
                </Stack>
              </Stack>
            </Card>
          </Stack>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-2)" justify="end">
          {currentStep > 1 && (
            <Button variant="ghost" onClick={handleBack}>
              Back
            </Button>
          )}
          {currentStep < 4 && (
            <Button variant="primary" onClick={handleNext}>
              Next
            </Button>
          )}
          {currentStep === 4 && (
            <Button variant="primary" onClick={handleNext}>
              Review
            </Button>
          )}
          {currentStep === 5 && (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // Local state for tasks, columns, and add form
  const [localTasks, setLocalTasks] = useState(props.tasks || []);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  // Sync local tasks with props
  useEffect(() => {
    setLocalTasks(props.tasks || []);
  }, [props.tasks]);

  // Listen to real-time task updates from other users
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setLocalTasks((prev) => [...prev, task]);
      } else if (action === 'move' && task) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === task.id ? { ...t, column: task.column } : t))
        );
      } else if (action === 'edit' && task) {
        setLocalTasks((prev) =>
          prev.map((t) => (t.id === task.id ? { ...t, ...task } : t))
        );
      } else if (action === 'delete' && task?.id) {
        setLocalTasks((prev) => prev.filter((t) => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    const grouped: Record<string, typeof localTasks> = {};
    (props.columns || []).forEach((col) => {
      grouped[col.id || ''] = [];
    });
    localTasks.forEach((task) => {
      const colId = task.column || 'todo';
      if (!grouped[colId]) grouped[colId] = [];
      grouped[colId].push(task);
    });
    return grouped;
  }, [localTasks, props.columns]);

  // Calculate stats
  const stats = useMemo(() => {
    const total = localTasks.length;
    const completed = localTasks.filter((t) => t.column === 'done').length;
    return { total, completed };
  }, [localTasks]);

  // Handle add task submission
  const handleAddTask = useCallback(
    (columnId: string) => {
      if (!newTaskTitle.trim()) return;
      const taskId = `task-${Date.now()}`;
      const newTask = {
        id: taskId,
        title: newTaskTitle,
        priority: newTaskPriority,
        column: columnId,
        assignee: '',
        dueDate: '',
      };
      setLocalTasks((prev) => [...prev, newTask]);
      taskUpdate({ action: 'create', taskId, data: newTask as any });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingToColumn(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  // Handle task move
  const handleMoveTask = useCallback(
    (taskId: string, toColumnId: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, column: toColumnId } : t))
      );
      taskUpdate({ action: 'move', taskId, data: { column: toColumnId } });
    },
    [taskUpdate]
  );

  // Handle task edit
  const handleEditTask = useCallback(
    (taskId: string, newTitle: string) => {
      setLocalTasks((prev) =>
        prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
      );
      taskUpdate({ action: 'edit', taskId, data: { title: newTitle } as any });
      setEditingTaskId(null);
    },
    [taskUpdate]
  );

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary bar */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center">
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" align="center">
              <Heading level={3}>Task Board</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {stats.completed} of {stats.total} completed
              </Text>
            </Stack>
          </Row>
        </Card>

        {/* Kanban columns */}
        <Row gap="var(--ggui-spacing-4)" justify="start" align="start">
          {(props.columns || []).map((column) => {
            const colTasks = tasksByColumn[column.id || ''] || [];
            return (
              <Box key={column.id} style={{ flex: '1 1 300px', minWidth: '300px' }}>
                <Stack gap="var(--ggui-spacing-3)">
                  {/* Column header */}
                  <Row justify="between" align="center">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="secondary" size="sm">
                      {colTasks.length}
                    </Badge>
                  </Row>

                  {/* Tasks list */}
                  <Stack gap="var(--ggui-spacing-2)" style={{ minHeight: '400px' }}>
                    {colTasks.map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="sm" as={Hoverable} hoverStyle={{ boxShadow: 'var(--ggui-shadow-md)' }}>
                        <Stack gap="var(--ggui-spacing-2)">
                          {/* Task title (editable on double-click) */}
                          {editingTaskId === task.id ? (
                            <Input
                              label="Edit task"
                              value={editTitle}
                              onChange={setEditTitle}
                              onKeyDown={(e: any) => {
