                              {task.title}
                            </Text>
                          )}

                          {/* Priority badge */}
                          {task.priority && (
                            <Badge
                              variant={
                                task.priority === 'high'
                                  ? 'error'
                                  : task.priority === 'medium'
                                    ? 'warning'
                                    : 'success'
