                              </Text>
                            )}
                          </Row>

                          {/* Move controls */}
                          <Dropdown
                            trigger={<Button variant="ghost" size="xs">Move</Button>}
                            options={(
                              props.columns || []
                            ).map((col) => ({
                              value: col.id || '',
                              label: col.name || '',
                            }))}
                            value={task.column || 'todo'}
                            onChange={(colId) => handleMoveTask(task.id || '', colId)}
                          />
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {/* Add task button / form */}
                  {addingToColumn === column.id ? (
                    <Card padding="var(--ggui-spacing-3)" shadow="sm" border={false} background="var(--ggui-color-primary-50)">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          placeholder="New task..."
                          value={newTaskTitle}
                          onChange={setNewTaskTitle}
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriority}
                          onChange={(v) => setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Row gap="var(--ggui-spacing-2)" justify="end">
                          <Button variant="ghost" size="sm" onClick={() => setAddingToColumn(null)}>
                            Cancel
                          </Button>
                          <Button
                            variant="primary"
                            size="sm"
                            onClick={() => handleAddTask(column.id || '')}
                          >
                            Add
                          </Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button
                      variant="outline"
                      fullWidth
                      onClick={() => setAddingToColumn(column.id || '')}
                    >
                      + Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Container>
  );
}

