interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





export default function Component(props: Props) {
  // State
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  // Derive category colors map
  const categoryColorMap = useMemo(() => {
    const colors: Record<string, string> = {
      'nonmetal': 'var(--ggui-color-primary-100)',
      'noble-gas': 'var(--ggui-color-success-100)',
      'halogen': 'var(--ggui-color-warning-100)',
      'alkali-metal': 'var(--ggui-color-error-100)',
      'alkaline-earth-metal': 'var(--ggui-color-info-100)',
      'transition-metal': 'var(--ggui-color-primary-50)',
      'lanthanide': 'var(--ggui-color-primary-200)',
      'actinide': 'var(--ggui-color-warning-200)',
      'metalloid': 'var(--ggui-color-neutral-200)',
      'metal': 'var(--ggui-color-neutral-100)',
    };
    return colors;
  }, []);

  // Get all unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  // Filter elements by search
  const filteredElements = useMemo(() => {
    if (!searchQuery) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name && el.name.toLowerCase().includes(query)) ||
      (el.symbol && el.symbol.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get background color for element
  const getElementColor = useCallback((element: typeof props.elements[0]) => {
    return categoryColorMap[element.category || ''] || 'var(--ggui-color-surface)';
  }, [categoryColorMap]);

  return (
    <Stack gap="var(--ggui-spacing-6)" align="stretch">
      {/* Search Input */}
      <Stack gap="var(--ggui-spacing-4)">
        <Heading level={1}>Periodic Table of Elements</Heading>
        <Input
          label="Search by element name or symbol"
          placeholder="e.g., Hydrogen, He"
          value={searchQuery}
          onChange={setSearchQuery}
          type="text"
        />
      </Stack>

      {/* Legend */}
      <Card padding="var(--ggui-spacing-4)" shadow="sm" aria-label="Element categories legend">
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ marginBottom: 'var(--ggui-spacing-3)' }}>Legend</Text>
        <Stack direction="horizontal" gap="var(--ggui-spacing-3)" wrap={true} align="center">
          {categories.map(category => (
            <Row key={category} gap="var(--ggui-spacing-2)" align="center">
              <Box
                background={categoryColorMap[category] || 'var(--ggui-color-surface)'}
                borderRadius="var(--ggui-shape-radius-sm)"
                padding="var(--ggui-spacing-2)"
                style={{ width: '24px', height: '24px' }}
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {category.replace('-', ' ').replace(/\b\w/g, char => char.toUpperCase())}
              </Text>
            </Row>
          ))}
        </Stack>
      </Card>

      {/* Periodic Table Grid */}
      <Box
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(18, 1fr)',
          gap: 'var(--ggui-spacing-2)',
          padding: 'var(--ggui-spacing-4)',
          background: 'var(--ggui-color-surface)',
          borderRadius: 'var(--ggui-shape-radius-lg)',
        }}
      >
        {filteredElements.map((element, idx) => {
          const gridRow = element.row || 1;
          const gridCol = element.col || 1;
          const isSelected = selectedElement?.atomicNumber === element.atomicNumber;
          const bgColor = getElementColor(element);

          return (
            <Card
              key={element.atomicNumber || idx}
              as={Clickable}
              onClick={() => setSelectedElement(element)}
              padding="var(--ggui-spacing-3)"
              shadow={isSelected ? 'md' : 'sm'}
              border={isSelected}
              style={{
                gridRow,
                gridColumn: gridCol,
                background: bgColor,
                cursor: 'pointer',
                transition: 'all 200ms ease-in-out',
                transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                position: 'relative',
              }}
            >
              {/* Atomic Number - Top Left */}
              <Text
                variant="caption"
                size="xs"
                color="var(--ggui-color-onSurfaceVariant)"
                style={{
                  position: 'absolute',
                  top: 'var(--ggui-spacing-1)',
                  left: 'var(--ggui-spacing-1)',
                }}
              >
                {element.atomicNumber}
              </Text>

              {/* Symbol - Centered, Large */}
              <Stack gap="var(--ggui-spacing-1)" align="center" justify="center">
                <Text
                  variant="label"
                  size="2xl"
                  weight="bold"
                  color="var(--ggui-color-onSurface)"
                  align="center"
                >
                  {element.symbol}
                </Text>
                <Text
                  variant="caption"
                  size="xs"
                  color="var(--ggui-color-onSurfaceVariant)"
                  align="center"
                >
                  {element.name}
                </Text>
              </Stack>
            </Card>
          );
        })}
      </Box>

      {/* Detail Panel */}
      {selectedElement && (
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2}>{selectedElement.name}</Heading>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Badge variant="primary" size="lg">
                  {selectedElement.symbol}
                </Badge>
                {selectedElement.category && (
                  <Badge variant="secondary">{selectedElement.category.replace('-', ' ').replace(/\b\w/g, char => char.toUpperCase())}</Badge>
                )}
              </Row>
            </Stack>
            <Divider />
            <Stack gap="var(--ggui-spacing-3)">
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                <Text variant="body" size="lg" weight="semibold">{selectedElement.atomicNumber}</Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                <Text variant="body" size="lg" weight="semibold">
                  {selectedElement.atomicWeight ? selectedElement.atomicWeight.toFixed(3) : 'N/A'}
                </Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category</Text>
                <Text variant="body" size="lg" weight="semibold">
                  {selectedElement.category ? selectedElement.category.replace('-', ' ').replace(/\b\w/g, char => char.toUpperCase()) : 'N/A'}
                </Text>
              </Stack>
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Position</Text>
                <Text variant="body" size="lg" weight="semibold">
                  Row {selectedElement.row}, Column {selectedElement.col}
                </Text>
              </Stack>
            </Stack>
            <Button variant="ghost" onClick={() => setSelectedElement(null)}>
              Close Details
            </Button>
          </Stack>
        </Card>
      )}
    </Stack>
  );
}

