interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State for tab navigation and quantity selector
  const [activeTab, setActiveTab] = useState<string>('description');
  const [quantity, setQuantity] = useState<number>(1);

  // Ensure product id and validate stock
  const productId = props.product.id || '';
  const stock = props.product.stock ?? 0;
  const isOutOfStock = stock === 0;
  const maxQuantity = Math.max(1, stock);

  // Helper: render star rating (1-5)
  const renderStars = (rating: number | undefined) => {
    const stars = [];
    const rate = Math.min(5, Math.max(0, rating ?? 0));
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <Icon
          key={`star-${i}`}
          name={i <= rate ? 'star' : 'star-outline'}
          size={16}
          color={i <= rate ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        />
      );
    }
    return stars;
  };

  // Handle quantity increment/decrement
  const handleQuantityChange = (delta: number) => {
    const newQty = Math.max(1, Math.min(maxQuantity, quantity + delta));
    setQuantity(newQty);
  };

  // Handle Add to Cart
  const handleAddToCart = () => {
    if (productId && !isOutOfStock) {
      addToCart({ productId, quantity });
    }
  };

  // Tab items
  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Text variant="body" color="var(--ggui-color-onSurface)" style={{ whiteSpace: 'pre-wrap' }}>
          {props.product.description || 'No description available.'}
        </Text>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: Array.isArray(props.product.specifications) && props.product.specifications.length > 0 ? (
        <Stack gap="var(--ggui-spacing-3)" direction="vertical">
          {props.product.specifications.map((spec: any, idx: number) => {
            const key = typeof spec === 'object' && spec !== null ? Object.keys(spec)[0] : `spec-${idx}`;
            const value = typeof spec === 'object' && spec !== null ? spec[key] : spec;
            return (
              <Row key={idx} gap="var(--ggui-spacing-4)" justify="start">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" style={{ minWidth: '120px' }}>
                  {String(key)}:
                </Text>
                <Text variant="body" color="var(--ggui-color-onSurface)">
                  {String(value)}
                </Text>
              </Row>
            );
          })}
        </Stack>
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          No specifications available.
        </Text>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: Array.isArray(props.product.reviews) && props.product.reviews.length > 0 ? (
        <Stack gap="var(--ggui-spacing-4)" direction="vertical">
          {props.product.reviews.map((review: any, idx: number) => {
            const author = review?.author || 'Anonymous';
            const rating = review?.rating ?? 0;
            const text = review?.text || '';
            const date = review?.date ? new Date(review.date).toLocaleDateString() : '';
            return (
              <Card key={idx} padding="var(--ggui-spacing-4)" shadow="sm" border>
                <Stack gap="var(--ggui-spacing-2)" direction="vertical">
                  <Row gap="var(--ggui-spacing-2)" justify="start" align="center">
                    <Text variant="label" weight="semibold">
                      {author}
                    </Text>
                    <Row gap="var(--ggui-spacing-1)" align="center">
                      {renderStars(rating)}
                    </Row>
                  </Row>
                  <Text variant="body" color="var(--ggui-color-onSurface)">
                    {text}
                  </Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {date}
                  </Text>
                </Stack>
              </Card>
            );
          })}
        </Stack>
      ) : (
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          No reviews yet.
        </Text>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" direction="vertical">
        {/* TOP SECTION: Product image, title, price, rating, stock */}
        <Stack gap="var(--ggui-spacing-6)" direction="horizontal" align="start">
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-8)"
            style={{ minWidth: '300px', minHeight: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack gap="var(--ggui-spacing-2)" direction="vertical" align="center" justify="center">
              <Icon name="image" size={48} color="var(--ggui-color-onSurfaceVariant)" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {props.product.name}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" direction="vertical" align="start" style={{ flex: 1 }}>
            <Heading level={1}>{props.product.name || 'Product'}</Heading>

            {/* Price */}
            <Heading level={2} color="var(--ggui-color-primary-600)">
              {props.product.currency || '$'} {(props.product.price ?? 0).toFixed(2)}
            </Heading>

            {/* Rating Stars */}
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Row gap="var(--ggui-spacing-1)" align="center">
                {renderStars(props.product.rating)}
              </Row>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {props.product.rating?.toFixed(1) || '0.0'} ({props.product.reviewCount ?? 0} reviews)
              </Text>
            </Row>

            {/* Stock Status Badge */}
            <Badge
              variant={stock > 5 ? 'success' : stock > 0 ? 'warning' : 'error'}
              size="md"
            >
              {stock > 0 ? (stock > 5 ? 'In Stock' : 'Low Stock') : 'Out of Stock'}
            </Badge>
          </Stack>
        </Stack>

        <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" />

        {/* MIDDLE SECTION: Tab Navigation */}
        <Stack gap="var(--ggui-spacing-4)" direction="vertical">
          <Tabs
            items={tabItems}
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            size="md"
          />
        </Stack>

        <Divider orientation="horizontal" margin="var(--ggui-spacing-4)" />

        {/* BOTTOM SECTION: Quantity selector and Add to Cart */}
        <Row gap="var(--ggui-spacing-4)" justify="start" align="center">
          {/* Quantity Selector */}
          <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
            <Text variant="label" color="var(--ggui-color-onSurface)">
              Quantity:
            </Text>
            <Button
              variant="outline"
              size="sm"
              onClick={() => handleQuantityChange(-1)}
              disabled={quantity <= 1}
            >
              −
            </Button>
            <Box
              padding="var(--ggui-spacing-2) var(--ggui-spacing-3)"
              background="var(--ggui-color-surfaceVariant)"
              borderRadius="var(--ggui-shape-radius-md)"
              style={{ minWidth: '50px', textAlign: 'center' }}
            >
              <Text variant="label" color="var(--ggui-color-onSurface)" align="center">
                {quantity}
              </Text>
            </Box>
            <Button
              variant="outline"
              size="sm"
              onClick={() => handleQuantityChange(1)}
              disabled={quantity >= maxQuantity}
            >
              +
            </Button>
          </Stack>

          {/* Add to Cart Button */}
          <Button
            variant="primary"
            size="lg"
            onClick={handleAddToCart}
            disabled={isOutOfStock}
          >
            {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

