  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State management
  const [messageText, setMessageText] = useState<string>('');
  const [allMessages, setAllMessages] = useState(props.messages);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const messagesContainerRef = useRef<HTMLDivElement>(null);


  // Auto-scroll to bottom when new messages arrive

  const scrollToBottom = useCallback(() => {
    if (messagesContainerRef.current) {
      messagesContainerRef.current.scrollTop = messagesContainerRef.current.scrollHeight;
    }
  }, []);

  // Scroll on mount and when messages change
  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  // Handle message send
  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: messageText, timestamp });
      setMessageText('');
    }
  }, [messageText, sendMessage]);

  // Handle Enter key in input
  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  // Determine if typing indicator should show
  const isTyping = typing.latest?.active && typing.latest?.sender !== props.currentUser;
  const typingUserName = typing.latest?.sender || 'Someone';

  // Format timestamp to readable format
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      return new Date(timestamp).toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
      });
    } catch {
      return '';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-4)">
      <Stack gap="var(--ggui-spacing-4)" align="stretch">
        {/* Header */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border={false} radius="md">
          <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface)">{props.title}</Heading>
            </Stack>
            <Badge variant="primary" size="sm">{props.participantCount} participant{props.participantCount !== 1 ? 's' : ''}</Badge>
          </Row>
        </Card>

        {/* Message List Container */}
        <Card padding="var(--ggui-spacing-4)" shadow="md" radius="lg" border={true}>
          <Stack gap="var(--ggui-spacing-3)" align="stretch" style={{ maxHeight: '400px', overflowY: 'auto' }} role="log" aria-label="Chat messages list" ref={messagesContainerRef}>
            {allMessages.length === 0 && !isTyping ? (
              <Box padding="var(--ggui-spacing-6)" background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)" role="status">
                <Text align="center" color="var(--ggui-color-onSurfaceVariant)" variant="body">
                  No messages yet. Start a conversation!
                </Text>
              </Box>
            ) : (
              allMessages.map((msg, index) => {
                const isOwnMessage = msg.sender === props.currentUser;
                const isSameAsPrevious = index > 0 && allMessages[index - 1].sender === msg.sender;

                return (
                  <Box key={index} padding="var(--ggui-spacing-2)" style={{ marginTop: isSameAsPrevious ? '0' : 'var(--ggui-spacing-2)' }} role="article">
                    {!isSameAsPrevious && (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ marginBottom: 'var(--ggui-spacing-1)' }}>
                        {msg.sender}
                      </Text>
                    )}
                    <Box
                      padding="var(--ggui-spacing-3)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={isOwnMessage ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                      style={{
                        marginLeft: isOwnMessage ? 'auto' : '0',
                        marginRight: isOwnMessage ? '0' : 'auto',
                        maxWidth: '70%',
                        wordWrap: 'break-word',
                      }}
                    >
                      <Text color={isOwnMessage ? 'var(--ggui-color-onPrimary, white)' : 'var(--ggui-color-onSurface)'} variant="body">
                        {msg.text}
                      </Text>
                      <Text color={isOwnMessage ? 'var(--ggui-color-onPrimary, rgba(255,255,255,0.7))' : 'var(--ggui-color-onSurfaceVariant)'} variant="caption" style={{ marginTop: 'var(--ggui-spacing-1)' }} aria-label={`Sent at ${formatTime(msg.timestamp)}`}>
                        {formatTime(msg.timestamp)}
                      </Text>
                    </Box>
                  </Box>
                );
              })
            )}

            {/* Typing Indicator */}
            {isTyping && (
              <Box padding="var(--ggui-spacing-2)" role="status" aria-live="polite" aria-label={`${typingUserName} is typing`}>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ fontStyle: 'italic' }}>
                  <Spinner size={12} color="var(--ggui-color-primary-600)" />
                  {' '}{typingUserName} is typing...
                </Text>
              </Box>
            )}

            {/* Auto-scroll marker */}
            <Box ref={messagesEndRef} style={{ height: 0, width: 0 }} />
          </Stack>
        </Card>

        {/* Input Area */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="end">
          <Input
            label="Message"
            placeholder="Type your message..."
            value={messageText}
            onChange={setMessageText}
            onKeyDown={handleKeyDown}
          />
          <Button
            variant="primary"
            size="md"
            onClick={handleSendMessage}
            disabled={messageText.trim() === ''}
            aria-label="Send message (Enter or Ctrl+Enter)"
          >
            Send
          </Button>
        </Stack>
      </Stack>
    </Container>
  );
}

