// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State: merge live updates with initial stock data
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [highlightedSymbols, setHighlightedSymbols] = useState<Set<string>>(new Set());
  const highlightTimeoutsRef = useRef<Record<string, NodeJS.Timeout>>({});
  const processedUpdatesRef = useRef<Set<string>>(new Set());

  // Update stocks when price updates arrive via stream
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      if (update.symbol && update.price !== undefined && update.change !== undefined && update.changePercent !== undefined) {
        const updateKey = `${update.symbol}-${update.price}-${Date.now()}`;
        if (!processedUpdatesRef.current.has(updateKey)) {
          processedUpdatesRef.current.add(updateKey);
          setStocks((prev) => {
            const existing = prev.find((s) => s.symbol === update.symbol);
            if (existing) {
              // Clear any existing timeout for this symbol
              if (highlightTimeoutsRef.current[update.symbol]) {
                clearTimeout(highlightTimeoutsRef.current[update.symbol]);
              }
              // Highlight the updated stock
              setHighlightedSymbols((hs) => new Set([...hs, update.symbol!]));
              // Remove highlight after 1.5 seconds
              highlightTimeoutsRef.current[update.symbol] = setTimeout(() => {
                setHighlightedSymbols((hs) => {
                  const next = new Set(hs);
                  next.delete(update.symbol!);
                  return next;
                });
                delete highlightTimeoutsRef.current[update.symbol];
              }, 1500);
              // Merge the update into the existing stock
              return prev.map((s) =>
                s.symbol === update.symbol
                  ? {
                      ...s,
                      price: update.price ?? s.price,
                      change: update.change ?? s.change,
                      changePercent: update.changePercent ?? s.changePercent,
                    }
                  : s
              );
            }
            return prev;
          });
          setLastUpdated(new Date());
        }
      }
    }
  }, [priceUpdate.latest]);

  // Cleanup timeouts on unmount
  useEffect(() => {
    return () => {
      Object.values(highlightTimeoutsRef.current).forEach(clearTimeout);
    };
  }, []);

  // Format price with 2 decimals
  const formatPrice = (price: number | undefined): string => {
    if (price === undefined || price === null) return 'N/A';
    return `$${price.toFixed(2)}`;
  };

  // Determine color for change (green for positive, red for negative)
  const getChangeColor = (change: number | undefined): string => {
    if (change === undefined || change === null) return 'var(--ggui-color-onSurface)';
    return change >= 0 ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  };

  // Get change arrow
  const getChangeArrow = (change: number | undefined): string => {
    if (change === undefined || change === null) return '';
    return change >= 0 ? '▲' : '▼';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Row justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)">
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated:
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
              {lastUpdated
                ? lastUpdated.toLocaleTimeString([], {
                    hour: '2-digit',
                    minute: '2-digit',
                    second: '2-digit',
                  })
                : 'N/A'}
            </Text>
          </Stack>
        </Row>

        {/* Stock Cards Grid */}
        <style>{`
          @keyframes ggui-pulse {
            0%, 100% { opacity: 1; }
            50% { opacity: 0.7; }
          }
        `}</style>
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: '1fr',
            gap: 'var(--ggui-spacing-4)',
          }}
          className="stock-grid-mobile"
        >
          <style>{`
            @media (min-width: 768px) {
              .stock-grid-mobile { grid-template-columns: repeat(2, 1fr); }
            }
            @media (min-width: 1024px) {
              .stock-grid-mobile { grid-template-columns: repeat(3, 1fr); }
            }
          `}</style>
          {stocks && stocks.length > 0 ? (
            stocks.map((stock) => {
              const changeColor = getChangeColor(stock.change);
              const isHighlighted = highlightedSymbols.has(stock.symbol || '');
              const borderColor =
                stock.change === undefined || stock.change === null
                  ? 'var(--ggui-color-outline)'
                  : stock.change >= 0
                    ? 'var(--ggui-color-success-500)'
                    : 'var(--ggui-color-error-500)';

              return (
                <Card
                  key={stock.symbol || Math.random()}
                  as={Hoverable}
                  padding="var(--ggui-spacing-4)"
                  shadow="md"
                  border={true}
                  radius="lg"
                  hoverStyle={{
                    opacity: 0.9,
                    boxShadow: 'var(--ggui-shape-shadow-lg)',
                  }}
                  style={
                    isHighlighted
                      ? {
                          borderColor: borderColor,
                          borderWidth: '2px',
                          animation: 'ggui-pulse 0.6s ease-in-out',
                          animationIterationCount: '2',
                        }
                      : {
                          borderColor: 'var(--ggui-color-outlineVariant)',
                        }
                  }
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    {/* Ticker Symbol */}
                    <Text variant="label" weight="bold" size="2xl">
                      {stock.symbol || 'N/A'}
                    </Text>

                    {/* Company Name */}
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      {stock.name || 'Unknown'}
                    </Text>

                    {/* Price */}
                    <Text variant="body" weight="medium" size="lg">
                      {formatPrice(stock.price)}
                    </Text>

                    {/* Change and Change Percent */}
                    <Row gap="var(--ggui-spacing-2)" align="center">
                      <Text color={changeColor} weight="medium">
                        {getChangeArrow(stock.change)} {stock.change?.toFixed(2) || 'N/A'}
                      </Text>
                      <Text color={changeColor} weight="medium">
                        ({stock.changePercent?.toFixed(2) || 'N/A'}%)
                      </Text>
                    </Row>
                  </Stack>
                </Card>
              );
            })
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant)">No stocks to display</Text>
          )}
        </Box>
       </Stack>
     </Container>
   );
}

