// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [profile, setProfile] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions?.[0] || '👤',
    role: props.initialProfile?.role || '',
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme || 'light',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  // Validation helpers
  const isValidEmail = useCallback((email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  }, []);

  const validateStep = useCallback((step: number): boolean => {
    const newErrors: Record<string, string> = {};

    if (step === 1) {
      if (!profile.name.trim()) {
        newErrors.name = 'Name is required';
      }
      if (!profile.email.trim()) {
        newErrors.email = 'Email is required';
      } else if (!isValidEmail(profile.email)) {
        newErrors.email = 'Please enter a valid email address';
      }
    }
    if (step === 2) {
      if (!profile.role) {
        newErrors.role = 'Please select a role';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  }, [profile, isValidEmail]);

  const handleNext = useCallback(() => {
    if (validateStep(currentStep)) {
      setCurrentStep(currentStep + 1);
      setErrors({});
    }
  }, [currentStep, validateStep]);

  const handleBack = useCallback(() => {
    setCurrentStep(Math.max(1, currentStep - 1));
    setErrors({});
  }, [currentStep]);

  const handleComplete = useCallback(() => {
    if (validateStep(currentStep)) {
      complete({
        name: profile.name,
        email: profile.email,
        avatar: profile.avatar,
        role: profile.role,
        emailNotifications: profile.emailNotifications,
        theme: profile.theme,
      });
    }
  }, [profile, validateStep, currentStep, complete]);

  const isStep1Valid = useMemo(() => {
    return profile.name.trim() !== '' && isValidEmail(profile.email);
  }, [profile.name, profile.email, isValidEmail]);

  const isStep2Valid = useMemo(() => {
    return profile.role !== '';
  }, [profile.role]);

  // Convert role options to SelectOption format
  const roleSelectOptions = useMemo(() => {
    return props.roleOptions?.map(role => ({
      value: role,
      label: role,
    })) || [];
  }, [props.roleOptions]);

  // Avatar options as SelectOption format
  const avatarSelectOptions = useMemo(() => {
    return props.avatarOptions?.map(avatar => ({
      value: avatar,
      label: avatar,
    })) || [];
  }, [props.avatarOptions]);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Step Indicator */}
        <Stack gap="var(--ggui-spacing-3)">
          <Row align="center" justify="between">
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
              Step {currentStep} of 3
            </Text>
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant)">
              {currentStep === 1 && 'Profile Setup'}
              {currentStep === 2 && 'Preferences'}
              {currentStep === 3 && 'Review & Confirm'}
            </Text>
          </Row>
          <Progress value={currentStep} max={3} size="md" />
        </Stack>

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Profile Setup</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Let's get to know you. Please fill in your basic information.
              </Text>

              {/* Name Input */}
              <Input
                label="Name"
                placeholder="Enter your full name"
                value={profile.name}
                onChange={(value) => setProfile({...profile, name: value})}
                error={errors.name}
                required
              />

              {/* Email Input */}
              <Input
                label="Email"
                type="email"
                placeholder="you@example.com"
                value={profile.email}
                onChange={(value) => setProfile({...profile, email: value})}
                error={errors.email}
                required
              />

              {/* Avatar Selection */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Choose Avatar
                </Text>
                <Row gap="var(--ggui-spacing-3)" wrap>
                  {props.avatarOptions?.map((avatar) => (
                    <Box
                      key={avatar}
                      as={Clickable}
                      onClick={() => setProfile({...profile, avatar})}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={profile.avatar === avatar ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                      hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                      style={{
                        cursor: 'pointer',
                        border: profile.avatar === avatar ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent',
                        transition: 'all 200ms ease-in-out',
                      }}
                    >
                       <Text size="lg">{avatar}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Preferences</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Customize your settings and preferences.
              </Text>

              {/* Role Selection */}
              <Select
                label="Role"
                value={profile.role}
                onChange={(value) => setProfile({...profile, role: value})}
                options={roleSelectOptions}
                placeholder="Select your role"
                error={errors.role}
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Enable email notifications"
                checked={profile.emailNotifications}
                onChange={(checked) => setProfile({...profile, emailNotifications: checked})}
                size="md"
              />

              {/* Theme Preference */}
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Theme Preference
                </Text>
                <Row gap="var(--ggui-spacing-3)">
                  <Box
                    as={Clickable}
                    onClick={() => setProfile({...profile, theme: 'light'})}
                    padding="var(--ggui-spacing-3)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    background={profile.theme === 'light' ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                    hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                    style={{
                      cursor: 'pointer',
                      border: profile.theme === 'light' ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent',
                      transition: 'all 200ms ease-in-out',
                      flex: 1,
                      textAlign: 'center',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      <Icon name="sun" size={24} />
                      <Text variant="label">Light</Text>
                    </Stack>
                  </Box>
                  <Box
                    as={Clickable}
                    onClick={() => setProfile({...profile, theme: 'dark'})}
                    padding="var(--ggui-spacing-3)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    background={profile.theme === 'dark' ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                    hoverStyle={{ background: 'var(--ggui-color-primary-50)' }}
                    style={{
                      cursor: 'pointer',
                      border: profile.theme === 'dark' ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent',
                      transition: 'all 200ms ease-in-out',
                      flex: 1,
                      textAlign: 'center',
                    }}
                  >
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      <Icon name="moon" size={24} />
                      <Text variant="label">Dark</Text>
                    </Stack>
                  </Box>
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 3: Review & Confirm */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2}>Review & Confirm</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                Please review your information before completing setup.
              </Text>

              {/* Review Summary */}
              <Stack gap="var(--ggui-spacing-3)">
                <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-3)">
                    {/* Name */}
                    <Row justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Name
                      </Text>
                      <Text variant="body" weight="semibold">
                        {profile.name}
                      </Text>
                    </Row>
                    <Divider />

                    {/* Email */}
                    <Row justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Email
                      </Text>
                      <Text variant="body" weight="semibold">
                        {profile.email}
                      </Text>
                    </Row>
                    <Divider />

                    {/* Avatar */}
                    <Row justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Avatar
                      </Text>
                       <Text variant="body">{profile.avatar}</Text>
                    </Row>
                    <Divider />

                    {/* Role */}
                    <Row justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Role
                      </Text>
                      <Text variant="body" weight="semibold">
                        {profile.role}
                      </Text>
                    </Row>
                    <Divider />

                    {/* Email Notifications */}
                    <Row justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Email Notifications
                      </Text>
                      <Badge variant={profile.emailNotifications ? 'success' : 'default'}>
                        {profile.emailNotifications ? 'Enabled' : 'Disabled'}
                      </Badge>
                    </Row>
                    <Divider />

                    {/* Theme */}
                    <Row justify="between" align="center">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                        Theme
                      </Text>
                      <Text variant="body" weight="semibold">
                        {profile.theme === 'light' ? 'Light' : 'Dark'}
                      </Text>
                    </Row>
                  </Stack>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="between">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Row gap="var(--ggui-spacing-2)">
            {currentStep < 3 && (
              <Button
                variant="primary"
                onClick={handleNext}
                disabled={currentStep === 1 && !isStep1Valid || currentStep === 2 && !isStep2Valid}
              >
                Next
              </Button>
            )}
            {currentStep === 3 && (
              <Button
                variant="primary"
                onClick={handleComplete}
              >
                Complete Setup
              </Button>
            )}
          </Row>
        </Row>
      </Stack>
    </Container>
  );
}
